mapper.select:
SELECT NVL(RESV_INTERVAL_MIN, 15)
  FROM TB_HOSPITAL
 WHERE HOSPITAL_ID = #{hospitalId}

SELECT (
    SELECT COUNT(*)
      FROM TB_RESERVATION R
     WHERE R.RESV_TYPE  = 'HOSPITAL'
       AND R.TARGET_ID  = TO_CHAR(#{hospitalId})
       AND R.DOCTOR_ID  = #{doctorId}
       AND R.RESV_DATE >= TRUNC(#{resvDate})
       AND R.RESV_DATE <  TRUNC(#{resvDate}) + 1
       AND R.STATUS_CD IN ('PENDING', 'CONFIRMED')
       AND R.RESV_TIME < #{endTime}
       AND NVL(
               R.END_TIME,
               TO_CHAR(
                   TO_DATE(R.RESV_TIME, 'HH24:MI')
                   + NUMTODSINTERVAL(NVL(R.DURATION_MIN, 30), 'MINUTE'),
                   'HH24:MI'
               )
           ) > #{resvTime}
) + (
    SELECT COUNT(*)
      FROM TB_HOSPITAL_RESV_HOLD H
     WHERE H.HOSPITAL_ID = #{hospitalId}
       AND H.DOCTOR_ID   = #{doctorId}
       AND H.RESV_DATE >= TRUNC(#{resvDate})
       AND H.RESV_DATE <  TRUNC(#{resvDate}) + 1
       AND H.EXPIRE_DATE > SYSDATE
       AND H.RESV_TIME < #{endTime}
       AND H.END_TIME > #{resvTime}

       AND H.HOLD_ID <> #{excludeHoldId}

)
  FROM DUAL

mapper.delete:
DELETE FROM TB_HOSPITAL_RESV_HOLD
 WHERE HOSPITAL_ID = #{hospitalId}
   AND MEMBER_NO   = #{memberNo}
